// src/components/Header.js
import React from "react";
import { Link } from "react-router-dom";

function Header() {
  const headerStyle = {
    backgroundColor: "#2c3e50",
    color: "white",
    padding: "15px 0",
    borderRadius: "8px",
    marginBottom: "20px",
    textAlign: "center",
  };

  const linkStyle = {
    color: "white",
    textDecoration: "none",
    fontSize: "1.8em",
    fontWeight: "bold",
  };

  return (
    <div style={headerStyle}>
      <Link to="/" style={linkStyle}>
        Deepfake Detection System
      </Link>
    </div>
  );
}

export default Header;
